(function(){'use strict';let clicksQueue=[];document.addEventListener('DOMContentLoaded',function(){if(!hasConsent()){return;}if(!isSampled()){return;}initTracker();});function getCookie(name){const value=`;${document.cookie}`;const parts=value.split(`;${name}=`);if(parts.length===2){return parts.pop().split(';').shift();}return null;}function hasConsent(){let consentPluginDetected=false;if(window.google_tag_data&&window.google_tag_data.ics&&window.google_tag_data.ics.entries){consentPluginDetected=true;const storage=window.google_tag_data.ics.entries.analytics_storage;if(storage&&(storage.current===false||storage.current==='denied')){return false;}}const complianz=getCookie('complianz_consent_status');if(complianz){consentPluginDetected=true;if(complianz!=='allow'){return false;}}const cli=getCookie('viewed_cookie_policy');if(cli){consentPluginDetected=true;if(cli!=='yes'){return false;}}const borlabs=getCookie('borlabs-cookie');if(borlabs){consentPluginDetected=true;if(borlabs.indexOf('statistics')===-1){return false;}}const requireConsent=parseInt(window.tracklyTrackerData.require_consent)===1;if(requireConsent&&!consentPluginDetected){return false;}return true;}function isSampled(){const rate=parseInt(window.tracklyTrackerData.sampling_rate)||100;if(rate>=100){return true;}let sampled=sessionStorage.getItem('trackly_is_sampled');if(sampled===null){const rand=Math.floor(Math.random()*100)+1;sampled=(rand<=rate)? 'true':'false';sessionStorage.setItem('trackly_is_sampled',sampled);}return sampled==='true';}function initTracker(){if(typeof window.tracklyTrackerAbort==='function'){try{window.tracklyTrackerAbort();}catch(e){}}const controller=new AbortController();const signalOption={signal:controller.signal};window.tracklyTrackerAbort=function(){controller.abort();};document.addEventListener('click',function(e){if(e.target.closest('#trackly-stats-bar-wrapper')){return;}if(window.tracklySelectorModeActive){return;}const selector=getUniqueSelector(e.target);const docWidth=Math.max(document.documentElement.clientWidth,document.body.scrollWidth,document.documentElement.scrollWidth,document.body.offsetWidth,document.documentElement.offsetWidth);const docHeight=Math.max(document.documentElement.clientHeight,document.body.scrollHeight,document.documentElement.scrollHeight,document.body.offsetHeight,document.documentElement.offsetHeight);const clickData={page_url:window.tracklyTrackerData.page_url,element_tag:e.target.tagName.toLowerCase(),element_selector:selector,click_x_pct:parseFloat(((e.pageX/docWidth)*100).toFixed(2)),click_y_pct:parseFloat(((e.pageY/docHeight)*100).toFixed(2))};clicksQueue.push(clickData);if(clicksQueue.length>=3){flushClicks();}},signalOption);window.addEventListener('pagehide',flushClicks,signalOption);window.addEventListener('visibilitychange',function(){if(document.visibilityState==='hidden'){flushClicks();}},signalOption);}function flushClicks(){if(clicksQueue.length===0){return;}const batch=clicksQueue.slice();clicksQueue=[];batch.forEach(function(click){fetch(window.tracklyTrackerData.rest_url+'/record-click',{method:'POST',headers:{'Content-Type':'application/json','X-WP-Nonce':window.tracklyTrackerData.nonce},body:JSON.stringify(click),keepalive:true}).catch(function(){});});}function getUniqueSelector(el){if(!(el instanceof HTMLElement)){return '';}let path=[];while(el.nodeType===Node.ELEMENT_NODE){let selector=el.nodeName.toLowerCase();if(el.id){selector+='#'+el.id;path.unshift(selector);break;}else{let className='';if(typeof el.className==='string'){className=el.className.trim();}else if(el.getAttribute){className=(el.getAttribute('class')||'').trim();}className=className.replace('.trackly-selector-hovered','');if(className){selector+='.'+className.replace(/\s+/g,'.');}let sib=el,nth=1;while(sib=sib.previousElementSibling){if(sib.nodeName.toLowerCase()===el.nodeName.toLowerCase()){nth++;}}if(nth!==1){selector+=':nth-of-type('+nth+')';}}path.unshift(selector);el=el.parentNode;}return path.join('>');}window.tracklyGetUniqueSelector=getUniqueSelector;})();